import React, { useState, useEffect } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';

// Fix for default markers
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

const LocationMarker = ({ position, setPosition, onLocationSelect }) => {
  useMapEvents({
    click(e) {
      const { lat, lng } = e.latlng;
      setPosition([lat, lng]);
      onLocationSelect(lat, lng);
    },
  });

  return position === null ? null : (
    <Marker 
      position={position} 
      draggable={true}
      eventHandlers={{
        dragend(e) {
          const { lat, lng } = e.target.getLatLng();
          setPosition([lat, lng]);
          onLocationSelect(lat, lng);
        },
      }}
    />
  );
};

const MapPicker = ({ onLocationSelect, initialLat = 27.7172, initialLng = 85.3240 }) => {
  const [position, setPosition] = useState([initialLat, initialLng]);

  useEffect(() => {
    setPosition([initialLat, initialLng]);
  }, [initialLat, initialLng]);

  const handleQuickSelect = (lat, lng) => {
    setPosition([lat, lng]);
    onLocationSelect(lat, lng);
  };

  return (
    <div style={styles.container}>
      <div style={styles.mapContainer}>
        <MapContainer
          center={position}
          zoom={13}
          style={styles.map}
          key={`${position[0]}-${position[1]}`}
        >
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />
          <LocationMarker 
            position={position} 
            setPosition={setPosition} 
            onLocationSelect={onLocationSelect}
          />
        </MapContainer>
      </div>

      <div style={styles.info}>
        <p style={styles.instructions}>
          📍 Click on the map or drag the marker to select location
        </p>
        <div style={styles.coordinates}>
          <span>Selected: {position[0].toFixed(6)}, {position[1].toFixed(6)}</span>
        </div>
      </div>

      <div style={styles.presetLocations}>
        <h5>Quick Select Cities:</h5>
        <button 
          onClick={() => handleQuickSelect(27.7172, 85.3240)}
          style={styles.presetBtn}
        >
          Kathmandu
        </button>
        <button 
          onClick={() => handleQuickSelect(28.2096, 83.9856)}
          style={styles.presetBtn}
        >
          Pokhara
        </button>
        <button 
          onClick={() => handleQuickSelect(26.4525, 87.2718)}
          style={styles.presetBtn}
        >
          Biratnagar
        </button>
      </div>
    </div>
  );
};

const styles = {
  container: {
    marginBottom: '1rem'
  },
  mapContainer: {
    border: '2px solid #d1d5db',
    borderRadius: '8px',
    overflow: 'hidden',
    marginBottom: '1rem'
  },
  map: {
    width: '100%',
    height: '400px'
  },
  info: {
    backgroundColor: '#f3f4f6',
    padding: '1rem',
    borderRadius: '6px',
    marginBottom: '1rem'
  },
  instructions: {
    margin: '0 0 0.5rem 0',
    color: '#374151',
    fontSize: '0.9rem'
  },
  coordinates: {
    fontSize: '0.8rem',
    color: '#6b7280',
    fontFamily: 'monospace'
  },
  presetLocations: {
    textAlign: 'center'
  },
  presetBtn: {
    backgroundColor: '#3b82f6',
    color: 'white',
    border: 'none',
    padding: '0.5rem 1rem',
    borderRadius: '4px',
    margin: '0 0.5rem',
    cursor: 'pointer',
    fontSize: '0.9rem'
  }
};

export default MapPicker;
